   getReadOptions(ctx: CrudContext<T>, opOptions: OpParams): CrudOptions {
@@
     return opts;
   }
+
+  private getKeysetPagination(opts: CrudOptions): {
+    sort: { field: string; direction: 'asc' | 'desc' }[];
+    orderBy: Record<string, any>[];
+    cursor?: Record<string, any>;
+  } | null {
+    if (opts.cursor && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.cursor && opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+    if (!opts.orderBy || !opts.limit) {
+      return null;
+    }
+
+    const orderBy = Array.isArray(opts.orderBy) ? opts.orderBy : [opts.orderBy];
+    const sort = orderBy.flatMap((part) =>
+      Object.entries(part).map(([field, value]) => ({
+        field,
+        direction: this.normalizeSortDirection(value),
+        value,
+      })),
+    );
+    const idField = this.crudConfig.id_field;
+    if (!sort.some((part) => part.field === idField)) {
+      sort.push({ field: idField, direction: 'asc', value: 'asc' });
+    }
+    if (new Set(sort.map((part) => part.field)).size !== sort.length) {
+      throw new BadRequestException('orderBy fields must be unique for cursor pagination');
+    }
+
+    const normalizedSort = sort.map(({ field, direction }) => ({
+      field,
+      direction,
+    }));
+    return {
+      sort: normalizedSort,
+      orderBy: sort.map(({ field, value }) => ({ [field]: value })),
+      cursor: opts.cursor
+        ? this.decodeCursor(opts.cursor, normalizedSort, idField)
+        : undefined,
+    };
+  }
+
+  private normalizeSortDirection(value: any): 'asc' | 'desc' {
+    const direction = String(value).toLowerCase();
+    if (direction.startsWith('asc')) return 'asc';
+    if (direction.startsWith('desc')) return 'desc';
+    throw new BadRequestException('orderBy directions must be asc or desc');
+  }
+
+  private decodeCursor(
+    cursor: string,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+    idField: string,
+  ): Record<string, any> {
+    let decoded: Record<string, any>;
+    try {
+      if (
+        !/^(?:[A-Za-z0-9+/]{4})*(?:[A-Za-z0-9+/]{2}==|[A-Za-z0-9+/]{3}=)?$/.test(
+          cursor,
+        )
+      ) {
+        throw new Error();
+      }
+      decoded = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('cursor must be valid Base64 JSON');
+    }
+    if (!decoded || typeof decoded !== 'object' || Array.isArray(decoded)) {
+      throw new BadRequestException('cursor must be valid Base64 JSON');
+    }
+    const expectedSort = sort
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (decoded.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    if (!(idField in decoded)) {
+      throw new BadRequestException('cursor is missing the entity ID');
+    }
+    for (const { field } of sort) {
+      if (!(field in decoded)) {
+        throw new BadRequestException(`cursor is missing sort field ${field}`);
+      }
+    }
+    decoded[idField] = this.dbAdapter.checkId(decoded[idField]);
+    return decoded;
+  }
+
+  private addKeysetCondition(
+    entity: Partial<T>,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+    cursor: Record<string, any>,
+  ): Partial<T> {
+    const cursorConditions = sort.map(({ field, direction }, index) => {
+      const condition: Record<string, any> = {};
+      for (let i = 0; i < index; i++) {
+        condition[sort[i].field] = cursor[sort[i].field];
+      }
+      condition[field] = { [direction === 'asc' ? '$gt' : '$lt']: cursor[field] };
+      return condition;
+    });
+    return { $and: [entity, { $or: cursorConditions }] } as Partial<T>;
+  }
+
+  private encodeCursor(
+    entity: T,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ): string {
+    const cursor: Record<string, any> = {
+      __sort: sort.map(({ field, direction }) => `${field}:${direction}`).join(','),
+    };
+    for (const { field } of sort) {
+      cursor[field] = entity[field];
+    }
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
