      .join('_')
      .toLowerCase();
  }

  getIncrementUpdate(
    increments: { [key: string]: number },
    entity: EntityClass<any>,
    ctx: CrudContext,
  ) {
    let updateSql = {};
    for (let key in increments) {
      if (key.includes('.')) {
        const [root, rest] = key.split(/\.(.*)/s);
        const columnName = this.convertColumnName(root);
        updateSql[root] = raw(
          `jsonb_set(COALESCE("${columnName}"::jsonb, '{}'::jsonb), '{${rest}}', (COALESCE("${columnName}"::text::jsonb->>'${rest}','0')::int + ${increments[key]})::text::jsonb)`,
